const hasWebhookEnvelope = Boolean($json && (Object.prototype.hasOwnProperty.call($json, 'body') || Object.prototype.hasOwnProperty.call($json, 'headers')));
const req = hasWebhookEnvelope ? ($json.body || {}) : ($json || {});
const rawMax = Number(req.max_per_source);
const maxPerSource = Number.isFinite(rawMax) && rawMax > 0 ? Math.min(Math.round(rawMax), 100) : 25;
return [{
  json: {
    run_id: $execution.id,
    run_ts: new Date().toISOString(),
    region: String(req.region || 'tunisia'),
    query: String(req.query || 'Tunisia'),
    workspace_id: req.workspace_id || null,
    max_per_source: maxPerSource,
    trigger_mode: hasWebhookEnvelope ? 'webhook' : 'schedule'
  }
}];

const raw = $json.body ?? $json.data ?? $json.response ?? $json;
const payload = typeof raw === "string" ? raw : JSON.stringify(raw);
return [{ json: { source_type: 'google_news_rss', source: 'google_news_rss', payload, error: $json.error ?? null, fetched_at: new Date().toISOString() } }];

const ctx = $node['TN Runtime Context'].json || {};
const rows = $input.all().map(i => i.json || {});
const sourceErrors = [];
const candidateSignals = [];
const now = new Date();
const nowIso = now.toISOString();
const region = String(ctx.region || 'tunisia');
const maxPerSource = Number(ctx.max_per_source || 25);
const addDays = (d) => new Date(now.getTime() + d * 86400000).toISOString();
const slug = (v) => String(v || "").toLowerCase().replace(/[^a-z0-9]+/g, "_").replace(/^_+|_+$/g, "").slice(0, 120) || "unknown";
const decodeHtml = (text) => String(text || "")
  .replace(/&amp;/g, "&")
  .replace(/&lt;/g, "<")
  .replace(/&gt;/g, ">")
  .replace(/&quot;/g, "\"")
  .replace(/&#39;/g, "'")
  .replace(/&#x27;/g, "'")
  .replace(/&#x2F;/g, "/");
const readTag = (block, tag) => {
  const cdata = block.match(new RegExp("<" + tag + "><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\\/" + tag + ">", "i"));
  if (cdata && cdata[1]) return decodeHtml(cdata[1].trim());
  const plain = block.match(new RegExp("<" + tag + ">([\\s\\S]*?)<\\/" + tag + ">", "i"));
  return plain && plain[1] ? decodeHtml(plain[1].trim()) : "";
};
for (const row of rows) {
  if (row.error) {
    sourceErrors.push({ source: row.source || "unknown", message: row.error.message || "source_failed" });
    continue;
  }
  if (row.source_type === "reddit") {
    const posts = row.payload?.data?.children || [];
    posts.slice(0, maxPerSource).forEach((p, idx) => {
      const d = p?.data || {};
      const title = String(d.title || "").trim();
      if (!title) return;
      const permalink = d.permalink ? ("https://www.reddit.com" + d.permalink) : null;
      candidateSignals.push({
        region,
        source: "reddit_search",
        signal_type: "social",
        signal_key: "tn_reddit_" + slug(title),
        signal_value: title,
        confidence: Number(Math.max(0.45, Math.min(0.85, 0.7 - idx * 0.01)).toFixed(3)),
        fetched_at: nowIso,
        expires_at: addDays(3),
        meta_json: { score: Number(d.score || 0), subreddit: d.subreddit || null, url: permalink }
      });
    });
  }
  if (row.source_type === "google_news_rss") {
    const xml = String(row.payload || "");
    const itemParts = xml.split("<item>");
    const items = itemParts.slice(1).map((part) => { const end = part.indexOf("</item>"); return end >= 0 ? ("<item>" + part.slice(0, end) + "</item>") : null; }).filter(Boolean);
    items.slice(0, maxPerSource).forEach((item, idx) => {
      const title = readTag(item, "title");
      const link = readTag(item, "link");
      const pubDate = readTag(item, "pubDate");
      if (!title) return;
      candidateSignals.push({
        region,
        source: "google_news_rss",
        signal_type: "news",
        signal_key: "tn_news_" + slug(title + "_" + link),
        signal_value: title,
        confidence: Number(Math.max(0.5, Math.min(0.9, 0.76 - idx * 0.01)).toFixed(3)),
        fetched_at: nowIso,
        expires_at: addDays(2),
        meta_json: { link: link || null, published_at: pubDate || null }
      });
    });
  }
  if (row.source_type === "gdelt") {
    const articles = Array.isArray(row.payload?.articles) ? row.payload.articles : [];
    articles.slice(0, maxPerSource).forEach((a, idx) => {
      const title = String(a?.title || "").trim();
      const url = String(a?.url || a?.sourceurl || "").trim();
      if (!title) return;
      candidateSignals.push({
        region,
        source: "gdelt_doc",
        signal_type: "news",
        signal_key: "tn_gdelt_" + slug(title + "_" + url),
        signal_value: title,
        confidence: Number(Math.max(0.45, Math.min(0.82, 0.7 - idx * 0.01)).toFixed(3)),
        fetched_at: nowIso,
        expires_at: addDays(2),
        meta_json: { url: url || null, language: a?.language || null, seendate: a?.seendate || null }
      });
    });
  }
}
const dedup = new Map();
for (const s of candidateSignals) {
  const key = s.signal_key;
  if (!dedup.has(key) || Number(dedup.get(key).confidence || 0) < Number(s.confidence || 0)) {
    dedup.set(key, s);
  }
}
const signals = Array.from(dedup.values()).sort((a, b) => Number(b.confidence || 0) - Number(a.confidence || 0));
return [{
  json: {
    run_id: ctx.run_id || null,
    run_ts: ctx.run_ts || nowIso,
    region,
    query: ctx.query || "Tunisia",
    workspace_id: ctx.workspace_id || null,
    trigger_mode: String(ctx.trigger_mode || 'schedule'),
    signals,
    signal_count: signals.length,
    source_error_count: sourceErrors.length,
    source_errors: sourceErrors,
    generated_at: nowIso
  }
}];

const base = $json || {};
let upserted = 0;
try {
  const row = $node['TN Upsert Market Signals'].json || {};
  upserted = Number(row.upserted_rows || 0);
} catch (e) {
  upserted = 0;
}
const top = (base.signals || []).slice(0, 5).map(s => s.signal_value).filter(Boolean);
const regionLabel = String(base.region || 'tunisia');
const summary = top.length ? ("Top " + regionLabel + " search signals: " + top.join(", ")) : ("No " + regionLabel + " signals found in this run");
return [{
  json: {
    ...base,
    status: base.signal_count > 0 ? "ok" : "no_data",
    upserted_rows: upserted,
    top_signals: top,
    summary_text: summary,
    completed_at: new Date().toISOString()
  }
}];
